from projection_inputs import DataQuality,PitcherModelInput
def build(x):
    skill="HIGH" if x.get("career_batters_faced",0)>=300 and x.get("season_batters_faced",0)>=200 else "MEDIUM"
    return PitcherModelInput(player=x["player"],pitcher_hand=x.get("pitcher_hand","R"),starter_confirmed=x.get("starter_confirmed",False),season_k_pct=x.get("season_k_pct",0),career_k_pct=x.get("career_k_pct",0),recent_k_pct=x.get("recent_k_pct",0),season_batters_faced=x.get("season_batters_faced",0),career_batters_faced=x.get("career_batters_faced",0),recent_batters_faced=x.get("recent_batters_faced",0),expected_batters_faced=x.get("expected_batters_faced",22),workload_floor=x.get("workload_floor",16),workload_ceiling=x.get("workload_ceiling",28),recent_pitch_counts=x.get("recent_pitch_counts",[]),opponent_lineup_k_pct=x.get("opponent_lineup_k_pct",.225),league_k_pct=x.get("league_k_pct",.225),lineup_confirmed=False,starter_role="NORMAL",data_quality=DataQuality(pitcher_skill=skill,lineup="LOW",workload="HIGH" if len(x.get("recent_pitch_counts",[]))>=3 else "MEDIUM",recent_change="LOW"))
